{
  "name": "search_issues",
  "description": "Search GitHub issues by query string, optionally filtered by state.",
  "parameters": {
    "type": "object",
    "properties": {
      "query": { "type": "string", "description": "Search query text" },
      "state": { "type": "string", "enum": ["open", "closed", "all"] },
      "limit": { "type": "integer", "description": "Max results to return" }
    },
    "required": ["query"]
  }
}

{
  "name": "create_release",
  "description": "Create a GitHub release with optional assets.",
  "parameters": {
    "type": "object",
    "properties": {
      "tag": { "type": "string" },
      "assets": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": { "path": { "type": "string" }, "label": { "type": "string" } },
          "required": ["path"]
        }
      }
    },
    "required": ["tag"]
  }
}
